def minWindow(s, t):
    need = collections.Counter(t); missing = len(t); i = l = r = 0
    for j, c in enumerate(s, 1):
        if need[c] > 0: missing -= 1
        need[c] -= 1
        if missing == 0:
            while i < j and need[s[i]] < 0: need[s[i]] += 1; i += 1
            if not r or j - i < r - l: l, r = i, j
    return s[l:r]

